 29â†’internal class ConstantFormatStructure<in T>(
 30â†’    val string: String
 31â†’) : NonConcatenatedFormatStructure<T> {
 32â†’    override fun toString(): String = "ConstantFormatStructure($string)"
 33â†’
 34â†’    override fun equals(other: Any?): Boolean = other is ConstantFormatStructure<*> && string == other.string
 35â†’    override fun hashCode(): Int = string.hashCode()
 36â†’
 37â†’    override fun parser(): ParserStructure<T> = ParserStructure(
 38â†’        operations = when {
 39â†’            string.isEmpty() -> emptyList()
 40â†’            else -> buildList {
 41â†’                val suffix = if (string[0].isAsciiDigit()) {
 42â†’                    add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(string.takeWhile {
 43â†’                        it.isAsciiDigit()
 44â†’                    }))))
 45â†’                    string.dropWhile { it.isAsciiDigit() }
 46â†’                } else {
 47â†’                    string
 48â†’                }
 49â†’                if (suffix.isNotEmpty()) {
 50â†’                    if (suffix[suffix.length - 1].isAsciiDigit()) {
 51â†’                        add(PlainStringParserOperation(suffix.dropLastWhile { it.isAsciiDigit() }))
 52â†’                        add(NumberSpanParserOperation(listOf(ConstantNumberConsumer(suffix.takeLastWhile {
 53â†’                            it.isAsciiDigit()
 54â†’                        }))))
 55â†’                    } else {
 56â†’                        add(PlainStringParserOperation(suffix))
 57â†’                    }
 58â†’                }
 59â†’            }
 60â†’        },
 61â†’        followedBy = emptyList()
 62â†’    )
 63â†’
 64â†’    override fun formatter(): FormatterStructure<T> = ConstantStringFormatterStructure(string)
 65â†’}
