222â†’internal sealed interface NonConcatenatedFormatStructure<in T> : FormatStructure<T>
223â†’
224â†’internal open class ConcatenatedFormatStructure<in T>(
225â†’    val formats: List<NonConcatenatedFormatStructure<T>>
226â†’) : FormatStructure<T> {
227â†’    override fun toString(): String = "ConcatenatedFormatStructure(${formats.joinToString(", ")})"
228â†’
229â†’    override fun equals(other: Any?): Boolean = other is ConcatenatedFormatStructure<*> && formats == other.formats
230â†’
231â†’    override fun hashCode(): Int = formats.hashCode()
232â†’
233â†’    override fun parser(): ParserStructure<T> = formats.map { it.parser() }.concat()
234â†’
235â†’    override fun formatter(): FormatterStructure<T> {
236â†’        val formatters = formats.map { it.formatter() }
237â†’        return if (formatters.size == 1) {
238â†’            formatters.single()
239â†’        } else {
240â†’            ConcatenatedFormatter(formatters)
241â†’        }
242â†’    }
243â†’}
