245â†’internal class CachedFormatStructure<in T>(formats: List<NonConcatenatedFormatStructure<T>>) :
246â†’    ConcatenatedFormatStructure<T>(formats) {
247â†’    private val cachedFormatter: FormatterStructure<T> = super.formatter()
248â†’    private val cachedParser: ParserStructure<T> = super.parser()
249â†’
250â†’    override fun formatter(): FormatterStructure<T> = cachedFormatter
251â†’
252â†’    override fun parser(): ParserStructure<T> = cachedParser
253â†’}
