            isoDayOfWeek.hashCode() * 31 +
            dayOfYear.hashCode()

    override fun toString(): String =
        "${year ?: "??"}-${monthNumber ?: "??"}-${dayOfMonth ?: "??"} (day of week is ${isoDayOfWeek ?: "??"})"
