 67â†’internal class SignedFormatStructure<in T>(
 68â†’    val format: FormatStructure<T>,
 69â†’    val withPlusSign: Boolean,
 70â†’) : NonConcatenatedFormatStructure<T> {
 71â†’
 72â†’    private val fieldSigns = basicFormats(format).mapNotNull { it.field.sign }.toSet()
 73â†’
 74â†’    init {
 75â†’        require(fieldSigns.isNotEmpty()) { "Signed format must contain at least one field with a sign" }
 76â†’    }
 77â†’
 78â†’    override fun toString(): String = "SignedFormatStructure($format)"
 79â†’
 80â†’    override fun equals(other: Any?): Boolean =
 81â†’        other is SignedFormatStructure<*> && format == other.format && withPlusSign == other.withPlusSign
 82â†’
 83â†’    override fun hashCode(): Int = 31 * format.hashCode() + withPlusSign.hashCode()
 84â†’
 85â†’    override fun parser(): ParserStructure<T> = listOf(
 86â†’        ParserStructure(
 87â†’            operations = listOf(
 88â†’                SignParser(
 89â†’                    isNegativeSetter = { value, isNegative ->
 90â†’                        for (field in fieldSigns) {
 91â†’                            val wasNegative = field.isNegative.getter(value) == true
 92â†’                            // TODO: replacing `!=` with `xor` fails on JS
 93â†’                            field.isNegative.trySetWithoutReassigning(value, isNegative != wasNegative)
 94â†’                        }
 95â†’                    },
 96â†’                    withPlusSign = withPlusSign,
 97â†’                    whatThisExpects = "sign for ${this.fieldSigns}"
 98â†’                )
 99â†’            ),
100â†’            emptyList()
101â†’        ), format.parser()
102â†’    ).concat()
103â†’
104â†’    override fun formatter(): FormatterStructure<T> {
105â†’        val innerFormat = format.formatter()
106â†’        fun checkIfAllNegative(value: T): Boolean {
107â†’            var seenNonZero = false
108â†’            for (check in fieldSigns) {
109â†’                when {
110â†’                    check.isNegative.getter(value) == true -> seenNonZero = true
111â†’                    check.isZero(value) -> continue
112â†’                    else -> return false
113â†’                }
114â†’            }
115â†’            return seenNonZero
116â†’        }
117â†’        return SignedFormatter(
118â†’            innerFormat,
119â†’            ::checkIfAllNegative,
120â†’            withPlusSign
121â†’        )
122â†’    }
123â†’}
