175â†’                                }
176â†’                            }
177â†’                        )
178â†’                    },
179â†’                    emptyList()
180â†’                )
181â†’            ).concat()
182â†’        )
183â†’    )
184â†’
185â†’    override fun formatter(): FormatterStructure<T> {
