259â†’            is ConcatenatedFormatStructure -> format.formats.forEach { rec(it) }
260â†’            is ConstantFormatStructure -> {}
261â†’            is SignedFormatStructure -> rec(format.format)
262â†’            is AlternativesParsingFormatStructure -> {
